window.ETS_LC3 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["He's fixing a file drawer.", "He's rolling up his sleeves.", "He's closing a laptop computer.", "He's drinking from a mug."], "optko": ["남자가 파일 서랍을 고치고 있다.", "남자가 소매를 걷어 올리고 있다.", "남자가 노트북 컴퓨터를 닫고 있다.", "남자가 머그잔에 든 것을 마시고 있다."], "ans": 3, "audio": "Test_03-01.mp3", "img": "ets_t3_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["Some bushes are covered with snow.", "Some flowers are being planted.", "A person is walking in the road.", "A person is cleaning some windows."], "optko": ["관목들이 눈으로 덮여 있다.", "꽃들이 심어지고 있다.", "사람이 도로를 걷고 있다.", "사람이 창문을 닦고 있다."], "ans": 0, "audio": "Test_03-02.mp3", "img": "ets_t3_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["A man is changing a tire on his car.", "A man is opening a car door.", "A man is putting fuel into his car.", "A man is spreading out a map on top of his car."], "optko": ["남자가 자동차의 타이어를 교체하고 있다.", "남자가 자동차 문을 열고 있다.", "남자가 자동차에 연료를 넣고 있다.", "남자가 자동차 위에 지도를 펼치고 있다."], "ans": 3, "audio": "Test_03-03.mp3", "img": "ets_t3_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["They're leaving a restaurant.", "They're seated next to each other.", "One of the women is looking in her handbag.", "One of the women is folding a scarf."], "optko": ["사람들이 레스토랑에서 나가고 있다.", "사람들이 나란히 앉아 있다.", "여자들 중 한 명이 핸드백 속을 들여다보고 있다.", "여자들 중 한 명이 스카프를 접고 있다."], "ans": 1, "audio": "Test_03-04.mp3", "img": "ets_t3_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["A selection of luggage is on display.", "A lamp and some papers are on a desk.", "Some boxes are arranged under some lamps.", "Some wire has been rolled up on the floor."], "optko": ["다양한 여행 가방이 진열되어 있다.", "전등과 서류들이 책상 위에 있다.", "상자들이 전등들 밑에 정돈되어 있다.", "전선이 바닥에 둥글게 말려 있다."], "ans": 2, "audio": "Test_03-05.mp3", "img": "ets_t3_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["A cyclist is riding past a pedestrian.", "A tent is set up next to a lake.", "Some people are resting on a stone wall.", "Some people are swimming in a lake."], "optko": ["자전거를 탄 사람이 보행자를 지나쳐 달리고 있다.", "텐트가 호수 옆에 설치되어 있다.", "사람들이 돌담 위에서 쉬고 있다.", "사람들이 호수에서 수영하고 있다."], "ans": 0, "audio": "Test_03-06.mp3", "img": "ets_t3_q6.jpg"}, {"n": 7, "part": 2, "q": "Where's the coffeemaker?", "qko": "커피메이커는 어디 있나요?", "opts": ["On the bottom shelf.", "A large serving spoon.", "It was discounted."], "optko": ["맨 아래 선반이에요.", "큰 서빙 스푼이요.", "그건 할인되었어요."], "ans": 0, "audio": "Test_03-07.mp3"}, {"n": 8, "part": 2, "q": "Why are you calling the clients?", "qko": "고객들에게 왜 전화하시나요?", "opts": ["A A spreadsheet with their contact information.", "B Because they canceled their order.", "C I can walk you there."], "optko": ["A 그분들의 연락처가 담긴 스프레드시트요.", "B 그분들이 주문을 취소했기 때문입니다.", "C 제가 안내해 드릴게요."], "ans": 1, "audio": "Test_03-08.mp3"}, {"n": 9, "part": 2, "q": "Would you like to attend our next company retreat?", "qko": "다음 회사 야유회에 참석하시겠어요?", "opts": ["A I'm parked next to that tree.", "B Yes, I'd like that.", "C Just some grilled vegetables."], "optko": ["A 저 나무 옆에 주차했어요.", "B 네, 그러고 싶어요.", "C 그릴에 구운 채소만요."], "ans": 1, "audio": "Test_03-09.mp3"}, {"n": 10, "part": 2, "q": "Who can update the Web site?", "qko": "누가 웹사이트를 업데이트할 수 있죠?", "opts": ["A I like the new Web site, too.", "B Kento said he could do it.", "C That's the right password."], "optko": ["A 저도 새 웹사이트가 마음에 듭니다.", "B 켄토가 할 수 있다고 말했어요.", "C 그게 맞는 비밀번호입니다."], "ans": 1, "audio": "Test_03-10.mp3"}, {"n": 11, "part": 2, "q": "Does your desk face the door or the window?", "qko": "당신 책상은 문을 향해 있나요, 아니면 창을 향해 있나요?", "opts": ["A It faces the door.", "B About forty minutes.", "C Because the room is too small."], "optko": ["A 문을 향해 있습니다.", "B 약 40분이요.", "C 방이 너무 작아서요."], "ans": 0, "audio": "Test_03-11.mp3"}, {"n": 12, "part": 2, "q": "When will your performance take place?", "qko": "당신 공연은 언제 하나요?", "opts": ["A Next Tuesday.", "B No, I just checked.", "C We shopped there yesterday."], "optko": ["A 다음 주 화요일이요.", "B 아니요, 제가 방금 확인했어요.", "C 저희는 어제 그곳에서 쇼핑했어요."], "ans": 0, "audio": "Test_03-12.mp3"}, {"n": 13, "part": 2, "q": "What will you get for completing the program?", "qko": "프로그램을 수료하면 무엇을 받으시나요?", "opts": ["A How many hours a week?", "B OK, thanks for asking.", "C A certificate in accounting."], "optko": ["A 일주일에 몇 시간이요?", "B 괜찮아요, 물어봐 주셔서 감사합니다.", "C 회계 분야의 자격증이요."], "ans": 2, "audio": "Test_03-13.mp3"}, {"n": 14, "part": 2, "q": "How did the company get its name?", "qko": "회사는 어떻게 그 이름을 갖게 되었나요?", "opts": ["A There's a new guest list.", "B Oh, about three years ago.", "C It's named after the owner."], "optko": ["A 신규 초대 손님 명단이 있어요.", "B 아, 약 3년 전에요.", "C 소유주의 이름을 따서 지었어요."], "ans": 2, "audio": "Test_03-14.mp3"}, {"n": 15, "part": 2, "q": "Your kitchen looks nice painted in this shade of yellow.", "qko": "이 노란 색조로 칠해진 주방이 멋져 보이네요.", "opts": ["A Twenty color copies, please.", "B Dinner will be ready in ten minutes.", "C Yes, it really brightens up the room."], "optko": ["A 컬러 복사로 20장 부탁합니다.", "B 저녁 식사가 10분 후에 준비될 겁니다.", "C 네, 공간을 정말로 화사하게 만들어 줘요."], "ans": 2, "audio": "Test_03-15.mp3"}, {"n": 16, "part": 2, "q": "Are you considering hiring a public relations firm?", "qko": "홍보 전문 업체를 고용하는 것을 고려하고 계신가요?", "opts": ["A I wasn't at that press conference.", "B No, we decided not to.", "C It's in the closet."], "optko": ["A 저는 그 기자 회견에 없었어요.", "B 아니요, 그러지 않기로 결정했어요.", "C 그건 수납장에 있어요."], "ans": 1, "audio": "Test_03-16.mp3"}, {"n": 17, "part": 2, "q": "Does this hallway lead to the lobby or to the courtyard?", "qko": "이 복도가 로비로 이어지나요, 아니면 안뜰로 이어지나요?", "opts": ["A My brother mentioned that.", "B How much does the box weigh?", "C To the lobby, I think."], "optko": ["A 제 남동생이 그 얘기 했어요.", "B 상자 무게가 얼마나 되나요?", "C 로비인 것 같아요."], "ans": 2, "audio": "Test_03-17.mp3"}, {"n": 18, "part": 2, "q": "The company's headquarters is in Houston, right?", "qko": "회사 본사가 휴스턴에 있죠, 그렇죠?", "opts": ["A This quarter's budget.", "B Let me look at the directory.", "C From nine to three."], "optko": ["A 이번 분기 예산이요.", "B 안내 책자를 확인해 볼게요.", "C 9시부터 3시까지지요."], "ans": 1, "audio": "Test_03-18.mp3"}, {"n": 19, "part": 2, "q": "Aren't the windows in the warehouse supposed to be replaced?", "qko": "창고 창문들을 교체하기로 되어 있지 않나요?", "opts": ["A Sure, I'll frame the picture.", "B No, I don't have any.", "C Mr. Bora ordered them."], "optko": ["A 네, 제가 그 사진을 액자에 넣을게요.", "B 아니요, 저는 없어요.", "C 보라 씨가 그것들을 주문했습니다."], "ans": 2, "audio": "Test_03-19.mp3"}, {"n": 20, "part": 2, "q": "Who's leading the workshop on Friday?", "qko": "누가 금요일에 워크숍을 진행하나요?", "opts": ["A Nice seeing you, too!", "B The other team has a ten-point lead.", "C It'll be Olga."], "optko": ["A 저도 만나서 반가웠습니다!", "B 상대팀이 10점 앞서고 있습니다.", "C 올가일 거예요."], "ans": 2, "audio": "Test_03-20.mp3"}, {"n": 21, "part": 2, "q": "Should we join our department's book club?", "qko": "우리 부서의 독서 동호회에 가입해야 할까요?", "opts": ["A An award-winning author.", "B The office supplies are in the storage room.", "C They could use a few more people."], "optko": ["A 수상 경력이 있는 작가요.", "B 사무용품은 창고에 있어요.", "C 그곳에 사람이 좀 더 필요할 거예요."], "ans": 2, "audio": "Test_03-21.mp3"}, {"n": 22, "part": 2, "q": "Shouldn't this package be returned?", "qko": "이 소포는 반송되어야 하지 않나요?", "opts": ["A Several packets of stamps from the post office.", "B Yes, it has to go back to the manufacturer.", "C Didn't she return from her trip last week?"], "optko": ["A 우체국에서 우표 여러 묶음이요.", "B 네, 제조사로 다시 보내야 해요.", "C 그녀는 여행에서 지난주에 돌아오지 않았나요?"], "ans": 1, "audio": "Test_03-22.mp3"}, {"n": 23, "part": 2, "q": "When will the training sessions for the new security measures take place?", "qko": "새 보안 조치를 위한 교육이 언제 열리나요?", "opts": ["A Yes, it was a complete success.", "B The upstairs conference room is large enough.", "C Not until the start of next month."], "optko": ["A 네, 그건 완벽한 성공이었어요.", "B 위층에 있는 대회의실은 충분히 넓어요.", "C 다음 달 초나 되어야 합니다."], "ans": 2, "audio": "Test_03-23.mp3"}, {"n": 24, "part": 2, "q": "Do you want the draft of the proposal e-mailed to you or printed out?", "qko": "제안서 초안을 이메일로 받길 원하세요, 아니면 출력된 것을 원하세요?", "opts": ["A Erina will be the one reviewing it.", "B They're too expensive.", "C I can arrange a client dinner."], "optko": ["A 에리나가 검토할 사람이에요.", "B 그것들은 너무 비싸요.", "C 제가 고객 저녁 식사 자리를 마련할 수 있어요."], "ans": 0, "audio": "Test_03-24.mp3"}, {"n": 25, "part": 2, "q": "Which day is most convenient for you?", "qko": "어느 요일이 가장 편하신가요?", "opts": ["A Yes, I'd appreciate it.", "B Well, the conference begins on Thursday.", "C Yes, it's under the passenger seat."], "optko": ["A 네, 감사합니다.", "B 음, 콘퍼런스가 목요일에 시작해요.", "C 네, 조수석 밑에 있어요."], "ans": 1, "audio": "Test_03-25.mp3"}, {"n": 26, "part": 2, "q": "Our department's looking for more interns.", "qko": "우리 부서는 인턴을 더 모집하고 있어요.", "opts": ["A My phone has an extended warranty.", "B What are the qualifications?", "C Yes, you completed your project."], "optko": ["A 제 전화기는 보증 기간이 연장되었습니다.", "B 자격 요건이 어떻게 되나요?", "C 네, 당신은 프로젝트를 완료했습니다."], "ans": 1, "audio": "Test_03-26.mp3"}, {"n": 27, "part": 2, "q": "How was your lunch at the park?", "qko": "공원에서의 점심 식사는 어떠셨나요?", "opts": ["A I had an unexpected client meeting.", "B Three sugars, please.", "C It's on the top shelf."], "optko": ["A 예기치 못한 고객 회의가 있었어요.", "B 설탕 세 스푼 넣어 주세요.", "C 그건 맨 위쪽 선반에 있어요."], "ans": 0, "audio": "Test_03-27.mp3"}, {"n": 28, "part": 2, "q": "Does your company send out the same promotional material every month?", "qko": "귀사에서는 매달 같은 홍보물을 발송하나요?", "opts": ["A We're going to try something new.", "B The bank across the street.", "C Niko just got promoted."], "optko": ["A 새로운 것을 시도해 보려고 해요.", "B 길 건너편에 있는 은행이요.", "C 니코가 막 승진했어요."], "ans": 0, "audio": "Test_03-28.mp3"}, {"n": 29, "part": 2, "q": "Where can I look at floor plans for our new office building?", "qko": "어디서 저희 새 사무실 건물의 평면도를 볼 수 있나요?", "opts": ["A Yes, I'd like some coffee.", "B A few more résumés.", "C I can ask the architect."], "optko": ["A 네, 커피로 할게요.", "B 이력서 몇 장 더요.", "C 건축가에게 물어볼게요."], "ans": 2, "audio": "Test_03-29.mp3"}, {"n": 30, "part": 2, "q": "Can I use the company car to pick up the clients from the airport?", "qko": "공항에서 고객들을 모시고 오기 위해 회사 차를 써도 될까요?", "opts": ["A Shenchao is the best project manager I know.", "B No, thanks—I've already been there.", "C The keys are on the desk over there."], "optko": ["A 셴차오가 제가 아는 최고의 프로젝트 관리자입니다.", "B 아니요, 괜찮습니다. 저는 이미 그곳에 가 봤어요.", "C 열쇠는 저기 책상 위에 있어요."], "ans": 2, "audio": "Test_03-30.mp3"}, {"n": 31, "part": 2, "q": "How often should our heating system be inspected?", "qko": "우리 난방 시스템은 얼마나 자주 점검되어야 하나요?", "opts": ["A Approximately $400.", "B Because I have a meeting at that time.", "C The recommendation is in the manual."], "optko": ["A 약 400달러요.", "B 제가 그 시간에 회의가 있어서요.", "C 권장 사항이 설명서에 나와 있어요."], "ans": 2, "audio": "Test_03-31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "M-Cn / W-Am", "audio": "Test_03-32-34.mp3", "qs": [{"n": 32, "q": "Where do the speakers most likely work?", "opts": ["At a shipping company", "At a restaurant", "At a gift shop", "At a farm"], "ans": 1, "ko": "남자가 첫 대사에서 여자를 셰프라고 부르고 있고, 많은 사람들이 비프 스튜 특선 요리를 주문한 것(Chef Ayaka. ~ I noticed that a lot of people ordered the beef stew special)과 관련해 이야기하고 있으므로 정답은 (B)이다."}, {"n": 33, "q": "What does the man suggest considering?", "opts": ["An advertising strategy", "An online menu", "The price of an item", "The results of a survey"], "ans": 2, "ko": "남자가 두 번째 대사에서 소고기 가격이 자주 바뀌기 때문에, 가격을 정할 때 그 부분을 고려해야 할 것(Beef prices change frequently, though, so we might need to consider that when we set the price for the dish ~)이라고 했으므로 정답은 (C)이다. [Paraphrasing: 대화의 Beef prices → 정답의 The price of an item]"}, {"n": 34, "q": "What does the woman say she will do?", "opts": ["Pay a deposit", "Contact a supplier", "Reschedule a delivery", "Arrange some merchandise"], "ans": 1, "ko": "여자가 마지막 대사에서 자신이 공급업체에 전화할 것(I'll call our supplier too)이라고 했으므로 정답은 (B)이다. [Paraphrasing: 대화의 call → 정답의 Contact]"}], "script": [{"sp": "M", "en": "Hi, Chef Ayaka. I was looking over this week's sales, and I noticed that a lot of people ordered the beef stew special.", "ko": "안녕하세요, 아야카 셰프님. 이번 주 판매량을 살펴보다가, 많은 분들이 비프 스튜 특선 요리를 주문하신 것을 알게 됐어요."}, {"sp": "W", "en": "Yeah. It's been very popular with patrons. In fact, I want to add it to the regular menu.", "ko": "네. 손님들에게 아주 인기가 많아요. 사실, 그걸 일반 메뉴에 추가하고 싶어요."}, {"sp": "M", "en": "Good idea. Beef prices change frequently, though, so we might need to consider that when we set the price for the dish if we're going to offer it daily.", "ko": "좋은 생각이에요. 하지만 소고기 가격이 자주 바뀌기 때문에, 그 요리를 매일 제공하려 한다면 가격을 정할 때 그 부분을 고려해야 할 거예요."}, {"sp": "W", "en": "OK. I'll call our supplier too. We need to make sure they can get us enough beef each week.", "ko": "알겠습니다. 제가 공급업체에도 전화할게요. 그들이 매주 충분한 양의 소고기를 공급해 줄 수 있어야 합니다."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Br / M-Cn (3인 대화)", "audio": "Test_03-35-37.mp3", "qs": [{"n": 35, "q": "Where is the conversation most likely taking place?", "opts": ["At a fitness center", "At a hotel", "At a train station", "At a corporate office"], "ans": 2, "ko": "첫 번째 남자가 첫 대사에서 1401번 열차가 렉싱턴 가 역에 정차하는지(~ does train 1401 stop at the Lexington Street station?) 물은 것과 여자가 두 번째 대사에서 열차가 3분 후에 12번 승강장에서 출발한다(The train leaves from platform twelve in three minutes)고 말한 것을 통해 기차역에서 대화 중임을 짐작할 수 있다. 따라서 정답은 (C)이다."}, {"n": 36, "q": "What type of event will the men attend this evening?", "opts": ["A company gala", "An opera", "A sports match", "A lecture"], "ans": 0, "ko": "두 번째 남자가 두 번째 대사에서 오늘 밤 회사 축하 행사가 정말 기대된다(I'm really looking forward to our company gala event tonight)고 했으므로 정답은 (A)이다. [Paraphrasing: 대화의 tonight → 질문의 this evening]"}, {"n": 37, "q": "What did Sergey forget to bring?", "opts": ["Gloves", "Sunglasses", "A hat", "An umbrella"], "ans": 3, "ko": "두 번째 남자가 첫 번째 남자를 세르게이라고 불렀고, 첫 번째 남자가 두 번째 대사에서 우산을 가져왔는지 물으며, 자신은 깜빡했다(Hey did you happen to bring an umbrella? I forgot mine)고 했으므로 정답은 (D)이다."}], "script": [{"sp": "M1", "en": "Excuse me, does train 1401 stop at the Lexington Street station?", "ko": "실례합니다. 1401번 열차가 렉싱턴 가 역에 정차하나요?"}, {"sp": "W", "en": "Yes. It's a twenty-minute ride.", "ko": "네. 20분 정도 걸립니다."}, {"sp": "M2", "en": "Oh good, that gives us plenty of time to get to the party.", "ko": "아, 잘됐네요. 그럼 파티에 가는 시간이 넉넉하네요."}, {"sp": "W", "en": "The train leaves from platform twelve in three minutes.", "ko": "그 열차는 3분 후에 12번 승강장에서 출발합니다."}, {"sp": "M2", "en": "Let's head over there now, Sergey. I'm really looking forward to our company gala event tonight.", "ko": "지금 그쪽으로 갑시다, 세르게이. 오늘 밤 우리 회사 축하 행사가 정말 기대돼요."}, {"sp": "M1", "en": "Me too. Hey did you happen to bring an umbrella? I forgot mine. It might rain on our walk from the station.", "ko": "저도요. 저기, 혹시 우산 가져왔어요? 저는 깜빡했네요. 역에서 걸어가는 동안 비가 올지도 몰라요."}, {"sp": "M2", "en": "I did! We can share it.", "ko": "가져왔어요! 같이 써요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Cn", "audio": "Test_03-38-40.mp3", "qs": [{"n": 38, "q": "What has Mr. Hoffman decided to do?", "opts": ["Extend store hours", "Start a delivery service", "Offer a rewards program", "Stop selling certain products"], "ans": 1, "ko": "여자가 첫 대사에서 호프먼 씨가 배송 서비스를 시작하기로 했다(~ he said he's decided to start a delivery service for our customers ~)고 했으므로 정답은 (B)이다."}, {"n": 39, "q": "What business do the speakers most likely work for?", "opts": ["A bakery", "A flower shop", "A grocery store", "A pharmacy"], "ans": 3, "ko": "남자가 첫 대사에서 많은 사람들이 약을 받기 위해 직접 오는 걸 불편하게 생각한다는 것을 알고 있다(I know a lot of people find it inconvenient to come in person to get their medications)고 했으므로 정답은 (D)이다."}, {"n": 40, "q": "What does the woman ask the man to help her do?", "opts": ["Mail some packages", "Take inventory", "Create a job posting", "Help some customers"], "ans": 2, "ko": "여자가 마지막 대사에서 배송 기사를 찾는 구인 공고 초안을 작성해야 한다며 그 일을 도와줄 수 있는지(~ I'm supposed to draft a job posting for delivery drivers. Could you help me do that?) 묻고 있으므로 정답은 (C)이다. [Paraphrasing: 대화의 draft → 정답의 Create]"}], "script": [{"sp": "W", "en": "I talked to Mr. Hoffman this morning, and he said he's decided to start a delivery service for our customers who have a difficult time picking up their prescriptions.", "ko": "오늘 오전에 호프먼 씨와 이야기했는데, 처방 약을 가져가기 힘든 고객들을 위해 배송 서비스를 시작하기로 하셨대요."}, {"sp": "M", "en": "That's a good idea. I know a lot of people find it inconvenient to come in person to get their medications. But many of our customers buy other things while they're here.", "ko": "좋은 생각입니다. 많은 사람들이 약을 받기 위해 직접 오는 걸 불편하게 생각한다는 것을 알고 있어요. 하지만 우리 고객 중 많은 분들께서 이곳에 오시면 다른 것들도 구매하시잖아요."}, {"sp": "W", "en": "Oh, they'll be able to make other purchases too, to be delivered with their medicine. In fact, I'm supposed to draft a job posting for delivery drivers. Could you help me do that?", "ko": "아, 다른 것들도 구매해서 약과 함께 배송받을 수 있을 겁니다. 사실, 제가 배송 기사를 찾는 구인 공고 초안을 작성해야 해요. 그 일을 도와주실 수 있으신가요?"}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Au", "audio": "Test_03-41-43.mp3", "qs": [{"n": 41, "q": "What problem does the woman mention?", "opts": ["A product is faulty.", "A company's sales are decreasing.", "Some materials are damaged.", "A sales department is understaffed."], "ans": 1, "ko": "여자가 첫 대사에서 안타깝게도 회사 매출이 계속 하락하고 있다(Unfortunately, our sales are continuing to drop)고 했으므로 정답은 (B)이다. [Paraphrasing: 대화의 are continuing to drop → 정답의 are decreasing]"}, {"n": 42, "q": "Where do the speakers most likely work?", "opts": ["At a publishing firm", "At a sporting goods company", "At a travel agency", "At a state park"], "ans": 1, "ko": "남자가 회사의 장비를 이용하는 운동선수들에게서 더 직접적인 의견을 받으면 도움이 될 것(we could probably benefit from having more direct input from athletes who use our gear)이라고 한 것에서 스포츠 용품 회사의 직원임을 알 수 있으므로 정답은 (B)이다."}, {"n": 43, "q": "What does the man say he will do this afternoon?", "opts": ["Sign a document", "Ship an order", "Review customer feedback", "Send a list"], "ans": 3, "ko": "남자가 마지막 대사에서 오늘 오후에 명단을 이메일로 보내겠다(I'll e-mail you a list this afternoon)고 했으므로 정답은 (D)이다."}], "script": [{"sp": "W", "en": "Marcel, I don't know if you reviewed the latest report. Unfortunately, our sales are continuing to drop.", "ko": "마르셀, 최신 보고서를 살펴보셨는지 모르겠네요. 안타깝게도, 우리 매출이 계속 하락하고 있어요."}, {"sp": "M", "en": "Yes, competition is at an all-time high. More and more companies are selling clothing and gear for outdoor recreation.", "ko": "네, 경쟁이 사상 최고 수준이에요. 점점 더 많은 회사들이 야외 여가 활동을 위한 의류와 장비를 판매하고 있어요."}, {"sp": "W", "en": "We need better ways to make our brand stand out.", "ko": "우리 브랜드를 돋보이게 만들 더 좋은 방안들이 필요해요."}, {"sp": "M", "en": "Well, we could probably benefit from having more direct input from athletes who use our gear. I was thinking maybe we could hire a professional rock climber to consult with our designers.", "ko": "음, 어쩌면 우리 장비를 이용하는 운동선수들에게 좀 더 직접적인 의견을 받으면 도움이 될 수 있을 거예요. 전문 암벽 등반 선수를 고용해 우리 디자이너들과 상의하면 어떨까 하는 생각을 했었어요."}, {"sp": "W", "en": "That's an interesting idea. Is there anyone you have in mind?", "ko": "흥미로운 아이디어군요. 생각해 두신 분이 있나요?"}, {"sp": "M", "en": "I'll e-mail you a list this afternoon.", "ko": "오늘 오후에 명단을 이메일로 보내 드릴게요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Cn", "audio": "Test_03-44-46.mp3", "qs": [{"n": 44, "q": "Why is the woman calling?", "opts": ["To verify some facts", "To confirm a deadline", "To inquire about an article", "To apply for a position"], "ans": 2, "ko": "여자가 첫 대사에서 약 5년 전에 자신이 신문 기사에 특집으로 실렸는데, 지금은 그 링크를 클릭하면 아무것도 나오지 않는다(I was featured in an article in your newspaper about five years ago. And now when I click on the link, nothing happens)고 했으므로 정답은 (C)이다."}, {"n": 45, "q": "What does the man offer to do?", "opts": ["Search a database", "Renew a subscription", "Consult with colleagues", "Send an updated schedule"], "ans": 0, "ko": "남자가 첫 대사에서 자사의 데이터베이스에서 여자가 말한 기사를 검색해 줄 수 있다(~ I can search for your article in our database)고 했으므로 정답은 (A)이다."}, {"n": 46, "q": "Why does the man congratulate the woman?", "opts": ["She appeared on television.", "She was nominated for an award.", "She is publishing a book.", "She is starting her own business."], "ans": 3, "ko": "여자가 세 번째 대사에서 개인 병원을 열기 때문에 기사를 벽에 걸어 놓고 싶다(~ now I'm starting my own practice. And I'd like to hang the article on the wall)고 설명하자, 남자가 축하 인사를 건네고 있으므로 정답은 (D)이다."}], "script": [{"sp": "W", "en": "Hello. I was featured in an article in your newspaper about five years ago. And now when I click on the link, nothing happens.", "ko": "안녕하세요. 제가 약 5년 전에 귀사의 신문 기사에 특집으로 실렸습니다. 그리고 지금 그 링크를 클릭하면, 아무것도 나오지 않습니다."}, {"sp": "M", "en": "Oh, the public links expire after three years, but I can search for your article in our database. I just need keywords from the article to use in the search.", "ko": "아, 공개 링크는 3년이 지나면 만료되지만, 저희 데이터베이스에서 그 기사를 검색해 드릴 수 있습니다. 검색에 사용할 기사의 키워드만 있으면 됩니다."}, {"sp": "W", "en": "It was about my internship at a dental office.", "ko": "치과에서의 인턴십에 관한 것이었어요."}, {"sp": "M", "en": "OK. Let me check our archives.", "ko": "알겠습니다. 저희 기록을 확인해 보겠습니다."}, {"sp": "W", "en": "Thanks. I was still in college when the article came out, but now I'm starting my own practice. And I'd like to hang the article on the wall.", "ko": "감사합니다. 제가 아직 대학교에 다니고 있을 때 그 기사가 나왔는데, 이제 제 개인 병원을 열어요. 그래서 그 기사를 벽에 걸어 놓고 싶어요."}, {"sp": "M", "en": "Oh! Congratulations.", "ko": "아! 축하드립니다."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Cn", "audio": "Test_03-47-49.mp3", "qs": [{"n": 47, "q": "Where does the conversation most likely take place?", "opts": ["At a furniture store", "At an electronics store", "At a sporting goods store", "At a building supply store"], "ans": 3, "ko": "여자가 첫 대사에서 모든 전동 공구와 사다리가 오늘 20퍼센트 할인된다(~ all our power tools and ladders are twenty percent off today)고 했으므로 정답은 (D)이다."}, {"n": 48, "q": "Why does the man want a refund?", "opts": ["He found a less expensive option.", "He bought the wrong size.", "He does not like the color of an item.", "He noticed an item is damaged."], "ans": 1, "ko": "남자가 첫 대사에서 구입한 판자가 너비가 맞지 않는다(~ the boards I purchased are the wrong width)고 했으므로 정답은 (B)이다."}, {"n": 49, "q": "What does the woman imply when she says, \"Let me find the manager\"?", "opts": ["She needs to attend to other customers.", "She does not have the authority to complete a request.", "A transaction was not processed correctly.", "A quality complaint needs to be documented."], "ans": 1, "ko": "여자가 두 번째 대사에서 영수증을 갖고 있는지(Do you have the receipt?) 묻는 것에 대해 남자가 그렇지 않다는 말과 함께 잃어버렸다(No, unfortunately. I must've lost it)고 대답하자, 여자가 인용문을 언급하고 있다. 이는 여자는 권한이 없으므로 권한이 있는 점장을 찾아보겠다는 뜻이므로 정답은 (B)이다."}], "script": [{"sp": "W", "en": "Welcome to Scott's Supplies! Just so you know, all our power tools and ladders are twenty percent off today. Is there something I can help you with?", "ko": "스캇츠 서플라이즈에 오신 것을 환영합니다! 참고로 말씀드리자면, 모든 전동 공구와 사다리가 오늘 20퍼센트 할인됩니다. 제가 도와드릴 게 있나요?"}, {"sp": "M", "en": "Yes. I came in last week to get some lumber for a home project I was working on, but the boards I purchased are the wrong width. I was wondering if I could get a refund.", "ko": "네. 지난주에 와서 제가 작업하고 있던 주택 프로젝트에 필요한 목재를 샀는데, 구입한 판자가 너비가 맞지 않아요. 환불을 받을 수 있는지 궁금했습니다."}, {"sp": "W", "en": "Sure. Do you have the receipt?", "ko": "물론입니다. 영수증을 갖고 계신가요?"}, {"sp": "M", "en": "No, unfortunately. I must've lost it.", "ko": "안타깝게도 없어요. 잃어버린 것 같아요."}, {"sp": "W", "en": "Hmm, OK. Let me find the manager.", "ko": "흠, 알겠습니다. 제가 점장님을 찾아보겠습니다."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Au", "audio": "Test_03-50-52.mp3", "qs": [{"n": 50, "q": "What most likely is the man's job?", "opts": ["Plumber", "Auto mechanic", "Food delivery person", "Computer technician"], "ans": 2, "ko": "여자가 첫 대사에서 남자에게 점심 식사 배달이 어땠는지(How were your lunch deliveries?) 묻고 있으므로 정답은 (C)이다."}, {"n": 51, "q": "What did the woman do while the man was gone?", "opts": ["She created an advertisement.", "She finalized a contract.", "She addressed a customer complaint.", "She had new software installed."], "ans": 3, "ko": "여자가 두 번째 대사에서 남자가 자리를 비운 동안 새로운 배달 소프트웨어를 설치해 작동시키고 있다(I got the new delivery software installed and running while you were gone)고 했으므로 정답은 (D)이다."}, {"n": 52, "q": "What does the woman say has recently changed?", "opts": ["Costs have been reduced.", "A competitor has opened a location nearby.", "The number of customers has increased.", "Safety regulations have been introduced."], "ans": 2, "ko": "여자가 마지막 대사에서 최근에 고객이 많이 증가했다(And since we've recently had such a significant increase in customers ~)고 했으므로 정답은 (C)이다."}], "script": [{"sp": "W", "en": "Welcome back! How were your lunch deliveries?", "ko": "돌아온 것을 환영합니다! 점심 식사 배달은 어떠셨나요?"}, {"sp": "M", "en": "All right, except one bag broke and the food container fell out right as I was walking up to a customer's door. The container was still sealed, and the customer accepted it, so it turned out OK in the end.", "ko": "괜찮았습니다. 봉투 하나가 찢어져서, 제가 고객의 집 문 앞으로 걸어 올라가고 있던 딱 그때 음식 용기가 떨어진 것만 빼면요. 용기가 그대로 밀봉되어 있었고, 고객께서 그것을 받아 주셔서 결과적으로는 괜찮았어요."}, {"sp": "W", "en": "Well, I'm glad everything worked out. By the way, take a look at my screen! I got the new delivery software installed and running while you were gone.", "ko": "음, 모든 게 잘돼서 다행이네요. 그건 그렇고, 제 화면을 한번 보세요! 자리를 비우신 동안 새로운 배달 소프트웨어를 설치해 작동시키고 있어요."}, {"sp": "M", "en": "This looks great! I like how different areas can be grouped together so drivers can deliver more efficiently.", "ko": "이거 굉장해 보이네요! 기사들이 더 효율적으로 배달할 수 있도록 여러 구역들을 함께 묶을 수 있다는 점이 마음에 듭니다."}, {"sp": "W", "en": "Me too. And since we've recently had such a significant increase in customers, this will be really useful.", "ko": "저도요. 그리고 최근에 고객이 많이 증가해서, 이게 정말 유용할 거예요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "M-Cn / W-Br", "audio": "Test_03-53-55.mp3", "qs": [{"n": 53, "q": "What type of company do the speakers work for?", "opts": ["An investment firm", "An advertising agency", "A staffing service", "A construction company"], "ans": 1, "ko": "남자가 첫 대사에서 새로운 고객과 광고 제작 계약을 체결했다(We signed a contract to create an ad campaign for a new client)고 했으므로 정답은 (B)이다."}, {"n": 54, "q": "What has HMD Incorporated recently done?", "opts": ["It has built a new headquarters.", "It has donated to a charity.", "It has developed a new line of products.", "It has won an industry award."], "ans": 2, "ko": "남자가 두 번째 대사에서 HMD 주식회사가 유기농 스낵 회사라는 말과 함께 완전히 채소로만 만들어진 스낵 신제품을 막 개발했다(It's HMD Incorporated, an organic snack company. They just developed a new line of snacks made entirely from vegetables)고 했으므로 정답은 (C)이다."}, {"n": 55, "q": "What does the man say he will do?", "opts": ["Update his team's goals", "Conduct some research", "Apply for a permit", "Arrange for a meeting"], "ans": 3, "ko": "남자가 마지막 대사에서 곧 회의 일정을 잡을 것(I'll schedule a meeting with them soon)이라고 했으므로 정답은 (D)이다."}], "script": [{"sp": "M", "en": "Hi, Jin-Ah. I've got good news. We signed a contract to create an ad campaign for a new client.", "ko": "안녕하세요, 진아. 좋은 소식이 있어요. 새로운 고객과 광고 제작 계약을 체결했어요."}, {"sp": "W", "en": "That's great! Who is it?", "ko": "잘됐네요! 그게 누구죠?"}, {"sp": "M", "en": "It's HMD Incorporated, an organic snack company. They just developed a new line of snacks made entirely from vegetables. They want to market the snacks to sports teams as well as individuals.", "ko": "HMD 주식회사인데, 유기농 스낵 회사입니다. 그곳에서 완전히 채소로만 만들어진 스낵 신제품을 막 개발했어요. 개인뿐 아니라 스포츠 팀들에게도 이 스낵을 마케팅하고 싶어 해요."}, {"sp": "W", "en": "Well, that sounds exciting but hard to understand. I guess we'll need to learn more about the products first.", "ko": "음, 흥미롭게 들리지만 이해하기 어렵네요. 먼저 그 제품에 관해 더 많이 알아야 할 것 같아요."}, {"sp": "M", "en": "Exactly. We'll have the client come in to give us nutritional information, and provide us with some samples. I'll schedule a meeting with them soon.", "ko": "맞아요. 고객이 방문하여 영양 정보를 전달하고 샘플을 제공하도록 할 것입니다. 제가 곧 회의 일정을 잡을 것입니다."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "3인 대화 W-Am / M-Au / W-Br", "audio": "Test_03-56-58.mp3", "qs": [{"n": 56, "q": "What did the man perform a maintenance check on?", "opts": ["A motorcycle", "A car", "A bus", "An airplane"], "ans": 3, "ko": "첫 번째 여자가 첫 대사에서 남자의 이름을 부르면서 소형 비행기의 관리 점검을 마쳤는지(Oliver, have you finished the maintenance check on the small airplane ~?) 물었고, 남자가 점검을 마쳤다(I finished checking it ~)고 했으므로 정답은 (D)이다."}, {"n": 57, "q": "What news does Camille share?", "opts": ["A delivery will be delayed.", "An expense will increase.", "A staff member is unavailable.", "A rainstorm is predicted."], "ans": 0, "ko": "남자가 첫 대사에서 카밀에게 새 펌프가 오늘 도착할지(Camille, will the new pump arrive today?) 묻자, 두 번째 여자가 유감스럽게도 아니라며, 제조사에서 지연될 거라고 했다(Unfortunately, no. The manufacturer said there'll be a delay, ~)고 답하므로 정답은 (A)이다."}, {"n": 58, "q": "Why is the customer traveling to Toronto?", "opts": ["To participate in a competition", "To present at a conference", "To attend a wedding", "To sign a contract"], "ans": 2, "ko": "첫 번째 여자가 마지막 대사에서 고객이 이번 주말에 친구 결혼식에 참석하기 위해 그 비행기를 타고 토론토에 갈 계획이었다(She was planning to fly the plane to Toronto this weekend for a friend's wedding)고 했으므로 정답은 (C)이다."}], "script": [{"sp": "W1", "en": "Oliver, have you finished the maintenance check on the small airplane that came in this morning? The owner's hoping to fly it this weekend.", "ko": "올리버, 오늘 오전에 들어온 소형 비행기의 관리 점검을 마치셨나요? 주인이 이번 주말에 비행하기를 원해요."}, {"sp": "M", "en": "I finished checking it earlier this morning. It needs a new fuel injection pump, so I've asked Camille to order one. Oh, here she comes. Camille, will the new pump arrive today?", "ko": "오늘 아침 일찍 점검을 마쳤어요. 새 연료 주입 펌프가 필요해서, 카밀에게 하나 주문해 달라고 요청했어요. 아, 여기 오네요. 카밀, 새 펌프가 오늘 도착할까요?"}, {"sp": "W2", "en": "Unfortunately, no. The manufacturer said there'll be a delay, and it won't arrive until Monday.", "ko": "유감스럽지만, 아니요. 제조사에서 지연될 거라고 했어요. 월요일에나 도착할 거예요."}, {"sp": "W1", "en": "I better let the customer know. She was planning to fly the plane to Toronto this weekend for a friend's wedding. She'll need to find another way to get there.", "ko": "고객님께 알려 드리는 게 좋겠군요. 이번 주말에 친구 결혼식에 참석하기 위해 그 비행기를 타고 토론토에 가실 계획이셨거든요. 그곳에 갈 다른 방법을 찾으셔야 하겠네요."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Br", "audio": "Test_03-59-61.mp3", "qs": [{"n": 59, "q": "What type of business does the man work for?", "opts": ["An electric company", "An Internet provider", "A landscaping service", "A water supplier"], "ans": 1, "ko": "남자가 첫 대사에서 여자에게 퀄리티 인터넷 서비스의 고객 서비스(~ you've reached the customer service line for Quality Internet Service)라고 했으므로 정답은 (B)이다."}, {"n": 60, "q": "What does the woman imply when she says, \"my company has asked me to relocate to Spain\"?", "opts": ["She enjoys traveling for business.", "She was surprised by a job transfer.", "She has no complaints about a service.", "She would like paperwork sent to a different address."], "ans": 2, "ko": "남자가 두 번째 대사에서 서비스에 문제가 있었는지(~ have you been experiencing issues with the service?) 묻자 여자가 인용문을 언급하고 있다. 이는 계정 해지의 이유가 서비스 문제가 아닌 다른 것임을 밝히는 말이므로 정답은 (C)이다."}, {"n": 61, "q": "What does the woman agree to do?", "opts": ["Pay a bill", "Read a policy", "Return a call", "Complete a survey"], "ans": 3, "ko": "남자가 네 번째 대사에서 전화를 끊지 말고 고객 경험에 관한 설문 조사에 응해 줄 것인지(~ would you be willing to stay on the phone line to take a survey about your experience as a customer?) 묻자, 여자가 물론(Certainly)이라고 했으므로 정답은 (D)이다."}], "script": [{"sp": "M", "en": "Hello, you've reached the customer service line for Quality Internet Service. How can I help you?", "ko": "안녕하세요, 퀄리티 인터넷 서비스의 고객 서비스입니다. 무엇을 도와드릴까요?"}, {"sp": "W", "en": "I'm Mona Shannak, and my account number's PK62H5. I'd like to close my account on June thirtieth.", "ko": "저는 모나 샤낙이고, 계정 번호는 PK62H5입니다. 6월 30일에 계정을 해지하고 싶어요."}, {"sp": "M", "en": "Oh, have you been experiencing issues with the service?", "ko": "아, 서비스에 문제가 있었나요?"}, {"sp": "W", "en": "Actually, my company has asked me to relocate to Spain.", "ko": "실은, 회사에서 스페인으로 전근을 요청했어요."}, {"sp": "M", "en": "That's exciting! I'll take care of your request for you then.", "ko": "멋지네요! 그럼 요청 사항을 처리해 드리겠습니다."}, {"sp": "W", "en": "Thank you—I appreciate that.", "ko": "감사합니다."}, {"sp": "M", "en": "When I'm done updating your records, would you be willing to stay on the phone line to take a survey about your experience as a customer?", "ko": "제가 기록 업데이트를 마치면, 전화를 끊지 마시고 고객 경험에 관한 설문 조사에 응해 주시겠어요?"}, {"sp": "W", "en": "Certainly.", "ko": "물론입니다."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "W-Am / M-Cn", "audio": "Test_03-62-64.mp3", "qs": [{"n": 62, "q": "Look at the graphic. Which dollar amount will the man change?", "opts": ["$2.37", "$4.55", "$7.86", "$2.91"], "ans": 0, "ko": "여자가 첫 대사에서 남자에게 손 세정제 디스펜서에 업데이트된 할인가 라벨을 부착해 줄 것(~ could you also put the updated sale-price labels on the hand soap dispensers?)을 요청하고 있다. 매장 선반에서 손 세정제 가격이 2.37달러로 표기되어 있으므로 정답은 (A)이다."}, {"n": 63, "q": "What will be added at the front of the store?", "opts": ["An additional checkout stand", "A holiday display", "A special food section", "A seating area"], "ans": 2, "ko": "여자가 두 번째 대사에서 매장 앞쪽에 새 해외 식품 코너를 위한 공간을 만들어 줄 것(Can you make room for our new international foods section at the front of the store?)을 요청하고 있으므로 정답은 (C)이다."}, {"n": 64, "q": "According to the man, why did a shipment arrive late?", "opts": ["He forgot to place an order.", "It was delivered to the wrong address.", "Some supplies were unavailable.", "Weather conditions were poor."], "ans": 3, "ko": "남자가 마지막 대사에서 배송품이 드디어 도착했는지 물으며, 북부 지역의 폭설이 배송 일정에 큰 영향을 미쳤다(Oh, did the shipment finally arrive? That snowstorm up north really affected delivery schedules)고 했으므로 정답은 (D)이다."}], "script": [{"sp": "W", "en": "Marco, you'll be restocking the cleaning products this morning, right? While you're doing that, could you also put the updated sale-price labels on the hand soap dispensers? They're on the shelf right above the laundry detergent.", "ko": "마르코, 오늘 오전에 청소용 제품들을 다시 채워 넣으실 거죠, 그렇죠? 그 일을 하시면서, 손 세정제 디스펜서에 업데이트된 할인가 라벨도 부착해 주실 수 있으세요? 세탁 세제 바로 위쪽 선반에 있어요."}, {"sp": "M", "en": "No problem—that shouldn't take long. What else can I help with?", "ko": "알겠습니다. 그 일은 오래 걸리지 않을 거예요. 또 무엇을 도와드릴까요?"}, {"sp": "W", "en": "Can you make room for our new international foods section at the front of the store?", "ko": "매장 앞쪽에 새 해외 식품 코너를 위한 공간을 만들어 주시겠어요?"}, {"sp": "M", "en": "Oh, did the shipment finally arrive? That snowstorm up north really affected delivery schedules.", "ko": "아, 배송품이 드디어 도착했나요? 북부 지역의 폭설이 배송 일정에 큰 영향을 미쳤잖아요."}], "gimg": "ets_t3_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "W-Br / M-Au", "audio": "Test_03-65-67.mp3", "qs": [{"n": 65, "q": "What does the man say he needs to have done?", "opts": ["He needs to schedule a job interview.", "He needs to cancel a doctor's appointment.", "He needs to have his photograph taken.", "He needs to renew his driver's license."], "ans": 2, "ko": "남자가 첫 대사에서 캐나다 여권용 사진을 찍어야 한다(I need to have a photo taken for a Canadian passport)고 했으므로 정답은 (C)이다."}, {"n": 66, "q": "What does the woman ask the man to bring to an appointment?", "opts": ["An application form", "Some references", "A study guide", "A payment receipt"], "ans": 0, "ko": "여자가 두 번째 대사에서 사이즈 요구 사항을 확인할 수 있도록 신청서만 한 부 가져오면 된다(Just bring in a copy of the application so we can see the size requirements)고 했으므로 정답은 (A)이다."}, {"n": 67, "q": "Look at the graphic. Which day will the man request an appointment for?", "opts": ["Monday", "Tuesday", "Wednesday", "Thursday"], "ans": 2, "ko": "여자가 마지막 대사에서 남자가 원하는 예약 시간과 관련해 일주일에 하루 오후 6시까지 문을 연다(We're open until six P.M. one day a week)고 했다. 일정표에서 영업 종료 시간이 오후 6시로 표기된 요일은 수요일이므로 정답은 (C)이다."}], "script": [{"sp": "W", "en": "Thanks for calling Kwon Photography Studio.", "ko": "권 포토 스튜디오에 전화해 주셔서 감사합니다."}, {"sp": "M", "en": "Hello. I need to have a photo taken for a Canadian passport.", "ko": "안녕하세요. 캐나다 여권용 사진을 찍어야 해요."}, {"sp": "W", "en": "OK. You can make an appointment Monday through Friday. Just bring in a copy of the application so we can see the size requirements.", "ko": "알겠습니다. 월요일부터 금요일까지 예약하실 수 있어요. 사이즈 요구 사항을 확인할 수 있도록 신청서만 한 부 가져오시면 됩니다."}, {"sp": "M", "en": "I work nine to five every day at my current job. Do you have any openings after five P.M.?", "ko": "제가 현재 직장에서 매일 9시부터 5시까지 근무를 해요. 오후 5시 후에 빈 시간대가 있을까요?"}, {"sp": "W", "en": "No problem. We're open until six P.M. one day a week.", "ko": "문제없습니다. 저희는 일주일에 하루 오후 6시까지 문을 열어요."}], "gimg": "ets_t3_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "M-Au / W-Am", "audio": "Test_03-68-70.mp3", "qs": [{"n": 68, "q": "What event did the woman attend last week?", "opts": ["A professional conference", "A training workshop", "A car auction", "A product demonstration"], "ans": 0, "ko": "남자가 첫 대사에서 여자에게 지난주에 참석한 치과 위생사 콘퍼런스에서 지출한 비용에 대한 영수증을 갖고 있는지(Do you have receipts for your expenses from the dental hygienists' conference you attended last week?) 묻고 있으므로 정답은 (A)이다."}, {"n": 69, "q": "What will the man do with the documents the woman provides?", "opts": ["Process a request", "Postpone a reservation", "Make a schedule", "Finalize a report"], "ans": 0, "ko": "남자가 두 번째 대사에서 여자가 보내는 영수증들을 받는 대로 환급 요청을 처리해 주겠다(Once I receive them, I'll process your request for reimbursement)고 했으므로 정답은 (A)이다."}, {"n": 70, "q": "Look at the graphic. Which section does the woman ask about?", "opts": ["Section 2", "Section 3", "Section 4", "Section 5"], "ans": 2, "ko": "여자가 두 번째 대사에서 부서 코드에 무엇을 사용해야 하는지(Remind me, what should I use for the department code?) 물었다. 양식에서 부서 코드가 쓰여 있는 섹션은 섹션 4이므로 정답은 (C)이다."}], "script": [{"sp": "M", "en": "Hi, Marina. Do you have receipts for your expenses from the dental hygienists' conference you attended last week?", "ko": "안녕하세요, 마리나. 지난주에 참석하셨던 치과 위생사 콘퍼런스에서 지출한 비용에 대한 영수증을 갖고 계신가요?"}, {"sp": "W", "en": "Yes, I have them. I was just going to scan them and send them to you by e-mail.", "ko": "네, 갖고 있어요. 그것들을 스캔해서 이메일로 보내려고 했어요."}, {"sp": "M", "en": "Thanks very much. Once I receive them, I'll process your request for reimbursement. Don't forget to fill out the travel expenses form and include it in your e-mail, too.", "ko": "대단히 감사합니다. 제가 받는 대로, 환급 요청을 처리해 드리겠습니다. 출장 경비 양식을 작성해서 이메일에 첨부하는 것도 잊지 마세요."}, {"sp": "W", "en": "OK. Remind me, what should I use for the department code?", "ko": "네. 부서 코드에 무엇을 사용해야 하는지 알려 주시겠어요?"}, {"sp": "M", "en": "Oh, sorry. I forgot to tell you. Use number 1009.", "ko": "아, 죄송합니다. 말씀드리는 걸 잊었네요. 1009번을 이용하시면 됩니다."}], "gimg": "ets_t3_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test_03-71-73.mp3", "qs": [{"n": 71, "q": "Which event is being planned?", "opts": ["A holiday parade", "A music festival", "A sports competition", "A company picnic"], "ans": 1, "ko": "화자가 초반부에 연례 음악 축제가 불과 몇 달밖에 남지 않았다(The town's annual music festival is only a few months away ~)고 언급하면서 그 행사의 계획과 관련해 이야기하고 있으므로 정답은 (B)이다."}, {"n": 72, "q": "What problem does the speaker mention?", "opts": ["A stage needs to be repainted.", "Some participants have canceled.", "There is not enough fencing.", "A parking area cannot be used."], "ans": 2, "ko": "화자가 중반부에 좌석 공간을 더 크게 만들 울타리가 충분하지 않다(However, we don't have enough fencing to create a larger seating area)고 했으므로 정답은 (C)이다."}, {"n": 73, "q": "What will Eniola most likely do today?", "opts": ["Select a caterer", "Hire a maintenance worker", "Confirm a start time", "Check a budget"], "ans": 3, "ko": "화자가 마지막에 에니올라에게 회계를 책임지고 있으니 울타리를 추가하기 위해 쓸 수 있는 자금이 있는지 오늘 중으로 확인해 달라(Eniola, since you're in charge of accounts, would you check sometime today to see whether we have money for extra fencing?)고 요청했으므로 정답은 (D)이다."}], "script": [{"sp": "W", "en": "The town's annual music festival is only a few months away, and our committee still has a lot of planning to do. We already have a list of performers who have agreed to appear. Fortunately, we can use the same stage and equipment we've used in the past. However, we don't have enough fencing to create a larger seating area. Eniola, since you're in charge of accounts, would you check sometime today to see whether we have money for extra fencing?", "ko": "시의 연례 음악 축제가 불과 몇 달밖에 남지 않았는데, 우리 위원회는 여전히 계획해야 할 일이 많습니다. 우리는 이미 출연에 동의한 공연자들의 명단을 갖고 있습니다. 다행히, 우리가 과거에 이용했던 것과 동일한 무대와 장비를 이용할 수 있습니다. 하지만 좌석 공간을 더 크게 만들 울타리가 충분하지 않습니다. 에니올라, 회계를 책임지고 계시니, 울타리를 추가하기 위해 쓸 수 있는 자금이 있는지 오늘 중으로 확인해 주시겠어요?"}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "W-Br", "audio": "Test_03-74-76.mp3", "qs": [{"n": 74, "q": "What type of event are the listeners most likely attending?", "opts": ["A trade show", "A press conference", "A charity auction", "A grand opening ceremony"], "ans": 0, "ko": "화자가 초반부에 청자들에게 부스에 들러 줘서 감사하다며, 모든 제조 관련 전시와 시연을 즐겼기를 바란다(I hope you've been enjoying all the manufacturing exhibits and demonstrations)고 했으므로 정답은 (A) 무역 박람회이다."}, {"n": 75, "q": "What does the speaker emphasize about a machine?", "opts": ["Its durability", "Its ease of use", "Its speed", "Its energy efficiency"], "ans": 2, "ko": "화자가 중반부에 자사의 기계가 2초마다 96개의 병뚜껑을 만들어 낼 수 있다며 믿을 수 없을 정도로 빠르다(This machine is able to create 96 bottle caps every two seconds. That's incredibly fast!)는 말을 덧붙이고 있으므로 정답은 (C) 속도이다."}, {"n": 76, "q": "What does the speaker offer the listeners?", "opts": ["A free sample", "A product discount", "A meal voucher", "A training brochure"], "ans": 1, "ko": "화자가 후반부에 이 기계를 주문하면 10퍼센트 할인해 준다(we're offering a ten percent discount on orders for this machine)고 했으므로 정답은 (B) 제품 할인이다."}], "script": [{"sp": "W", "en": "Hello, everyone! Thanks for stopping by my booth. I hope you've been enjoying all the manufacturing exhibits and demonstrations. I'm Carmen Fuentes, and I'm a sales representative at LT Plastic Injectors. Today I'm delighted to show you one of our new injection molding machines. It's currently fitted with a mold to make plastic bottle caps. This machine is able to create 96 bottle caps every two seconds. That's incredibly fast! And for today only, we're offering a ten percent discount on orders for this machine just for attending our demonstration.", "ko": "안녕하세요, 여러분! 저희 부스에 들러 주셔서 감사합니다. 모든 제조 관련 전시와 시연을 즐기셨기를 바랍니다. 저는 카르멘 푸엔테스이고, LT 플라스틱 인젝터스의 영업 사원입니다. 오늘 여러분께 새로운 사출 성형 기계 중 하나를 보여 드리게 되어 기쁩니다. 이 제품은 현재 플라스틱 병뚜껑을 만들기 위한 틀이 장착되어 있습니다. 이 기계는 2초마다 96개의 병뚜껑을 만들어 낼 수 있습니다. 믿을 수 없을 정도로 빠릅니다! 그리고 오늘 단 하루, 시연회에 참석하신 분들에게만 이 기계를 주문하시면 10퍼센트 할인해 드립니다."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test_03-77-79.mp3", "qs": [{"n": 77, "q": "What industry does the speaker work in?", "opts": ["Food manufacturing", "Building construction", "Computer technology", "Entertainment"], "ans": 2, "ko": "화자가 초반부에 소속 회사가 가장 큰 컴퓨터 칩 제조사 중 하나였다(we've been one of the largest manufacturers of computer chips)고 했으므로 정답은 (C) 컴퓨터 기술이다."}, {"n": 78, "q": "Why is the company making a change?", "opts": ["To create employment opportunities", "To reduce manufacturing costs", "To comply with a government policy", "To increase control over quality"], "ans": 3, "ko": "화자가 중반부에 생산하는 기술의 품질을 더 잘 통제하기 위해 이러한 변경을 결정했다(We've decided to make this change to allow us to have more control over the quality of the technology we produce)고 했으므로 정답은 (D) 품질에 대한 통제를 높이기 위해이다."}, {"n": 79, "q": "What will be sent out later in the morning?", "opts": ["Work assignments", "Calendar invitations", "A press release", "Product specifications"], "ans": 0, "ko": "화자가 후반부에 일부 직원들은 앞으로 새로운 업무를 배정받을 것이며, 그렇게 배정된 업무는 오전 중으로 전달될 것(some employees will have new work assignments going forward. Those assignments will be communicated later in the morning)이라고 했으므로 정답은 (A) 배정된 업무이다."}], "script": [{"sp": "W", "en": "The company leadership here at PCF Technologies has decided to make a major change. Historically, we've been one of the largest manufacturers of computer chips. However, starting next month, our company will launch a research and development division and start designing chips, too. We've decided to make this change to allow us to have more control over the quality of the technology we produce. As a result, some employees will have new work assignments going forward. Those assignments will be communicated later in the morning.", "ko": "PCF 테크놀로지스의 회사 경영진은 큰 변화를 주기로 결정했습니다. 역사적으로, 우리는 가장 큰 컴퓨터 칩 제조사 중 하나였습니다. 하지만 다음 달부터 우리 회사는 연구 개발부를 출범해 칩을 설계하는 일도 시작할 것입니다. 우리가 생산하는 기술의 품질을 더 잘 통제하기 위해 이러한 변경을 결정했습니다. 그 결과, 일부 직원들은 앞으로 새로운 업무를 배정받게 됩니다. 그렇게 배정된 업무는 오전 중으로 전달될 예정입니다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test_03-80-82.mp3", "qs": [{"n": 80, "q": "What is the focus of the podcast?", "opts": ["Technology", "Agriculture", "Finance", "Cooking"], "ans": 1, "ko": "화자가 초반부에 농업 분야의 모든 최신 뉴스를 다루는 팟캐스트(a podcast all about the latest news in agriculture)라고 했으므로 정답은 (B) 농업이다."}, {"n": 81, "q": "Why does the speaker apologize?", "opts": ["For having some audio problems", "For delaying some Web site updates", "For forgetting to thank a sponsor", "For providing an incorrect date"], "ans": 3, "ko": "화자가 중반부에 지난주 방송에서 농업 박람회의 날짜를 잘못 알려 준 것(I'd like to note that I provided the wrong dates for the Farming Exposition during last week's episode)을 언급하면서, 날짜를 정정하고 사과했으므로 정답은 (D) 잘못된 날짜를 알려 주었기 때문에이다."}, {"n": 82, "q": "Who is Junko Adachi?", "opts": ["The director of a nonprofit organization", "The president of a national bank", "A successful inventor", "A well-known author"], "ans": 0, "ko": "화자가 후반부에 준코 아다치 씨는 소규모 농장에 저가 비료를 제공하는 비영리 단체인 퍼틸라이저 원의 이사(Ms. Junko Adachi is the director at Fertilizer-ONE—a nonprofit organization that provides small farms with low-cost fertilizer)라고 했으므로 정답은 (A) 비영리 단체의 이사이다."}], "script": [{"sp": "M", "en": "Hello! Welcome to Ag-Cast—a podcast all about the latest news in agriculture. Before we get started with today's episode, I'd like to note that I provided the wrong dates for the Farming Exposition during last week's episode. The start date of the event is March thirty-first, not the twenty-first. I'm sorry about that. OK, let's move on to today's guest. Ms. Junko Adachi is the director at Fertilizer-ONE—a nonprofit organization that provides small farms with low-cost fertilizer. During her time as director, the organization has helped over 1,000 small farms increase their yields!", "ko": "안녕하세요! 농업 분야의 모든 최신 뉴스를 다루는 팟캐스트, 〈애그 캐스트〉에 오신 것을 환영합니다. 오늘 방송을 시작하기에 앞서, 지난주 방송에서 농업 박람회의 날짜를 잘못 알려 드렸다는 점 말씀드립니다. 이 행사의 시작 날짜는 3월 21일이 아니라 31일입니다. 이에 대해 사과드립니다. 자, 오늘 초대 손님 순서로 넘어가겠습니다. 준코 아다치 씨는 소규모 농장에 저가 비료를 제공하는 비영리 단체인 퍼틸라이저 원의 이사입니다. 이분이 이사로 재직하는 동안, 이 단체는 1,000개가 넘는 소규모 농장의 수확량 증대를 도왔습니다!"}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "W-Br", "audio": "Test_03-83-85.mp3", "qs": [{"n": 83, "q": "What industry does the speaker work in?", "opts": ["Real estate", "Construction", "Technology", "Manufacturing"], "ans": 1, "ko": "화자가 초반부에 자신의 이름을 언급하면서 개조 공사 프로젝트 작업을 하고 있는 공사팀 감독(This is Susana, the supervisor of the construction crew working on your renovation project)이라고 했으므로 정답은 (B) 건설이다."}, {"n": 84, "q": "According to the speaker, what has caused a problem?", "opts": ["Bad weather", "An employee absence", "A supply shortage", "The age of a building"], "ans": 3, "ko": "화자가 중반부에 청자의 주택은 오래 전에 지어져 수년에 걸쳐 내려앉았고, 이로 인해 일부 창틀에 정렬 문제가 발생했다(Your house was built a long time ago and has settled over the years. Unfortunately, this has caused some frame alignment issues)고 했으므로 정답은 (D) 건물의 나이이다."}, {"n": 85, "q": "Why does the speaker say, \"I'll be available for the next couple of hours\"?", "opts": ["To inform the listener of new business hours", "To confirm the listener's appointment", "To remind the listener to submit a payment", "To encourage the listener to call back soon"], "ans": 3, "ko": "화자가 후반부에 내일까지는 어떻게 진행할지 알아야 한다(we'll need to know how to proceed by tomorrow)면서 인용문을 언급하고 있다. 이는 자신과 통화 가능한 시간대를 알려줌으로써 결정 사항과 관련해 회신해 달라는 뜻이므로 정답은 (D) 청자에게 곧 다시 전화하도록 권하기 위해이다."}], "script": [{"sp": "W", "en": "Hi, Mr. Flores. This is Susana, the supervisor of the construction crew working on your renovation project. I'm calling because we've run into an issue with the front window replacements. Your house was built a long time ago and has settled over the years. Unfortunately, this has caused some frame alignment issues. We will not be able to install the new bay window you requested for the front room without more extensive work than the budget will cover. Our work is done for today, but we'll need to know how to proceed by tomorrow. I'll be available for the next couple of hours.", "ko": "안녕하세요, 플로레스 씨. 귀하의 개조 공사 프로젝트 작업을 하고 있는 공사팀 감독, 수잔나입니다. 전면 창 교체와 관련된 문제가 발생하여 전화를 드립니다. 귀하의 주택은 오래 전에 지어져 수년에 걸쳐 내려앉았습니다. 유감스럽게도, 이로 인해 일부 창틀에 정렬 문제가 발생했습니다. 예산으로 충당할 수 있는 범위보다 더 광범위한 작업을 하지 않고는 앞쪽 방에 요청하신 새 돌출형 창을 설치할 수 없을 겁니다. 오늘 작업은 끝났지만, 내일까지는 어떻게 진행할지 알아야 합니다. 저는 앞으로 두어 시간 동안 연락 가능합니다."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "M-Cn", "audio": "Test_03-86-88.mp3", "qs": [{"n": 86, "q": "Who most likely is the speaker?", "opts": ["A marketing consultant", "A bank manager", "A hospital director", "A factory owner"], "ans": 1, "ko": "화자가 초반부에 소속 은행 지점이 본사 감사관으로부터 평가를 받았던 것(our bank branch was evaluated by auditors from our headquarters last week)을 언급했고, 이어 그 결과에 대해서 말하고 있다. 따라서 정답은 (B) 은행장이다."}, {"n": 87, "q": "According to the speaker, what were some auditors impressed with?", "opts": ["Customer service", "Employee satisfaction", "Community outreach", "Worker safety"], "ans": 0, "ko": "화자가 중반부에 회계 감사관들이 고객 서비스 품질에 깊은 인상을 받았다(they were impressed with the quality of our customer service, ~)고 했으므로 정답은 (A) 고객 서비스이다."}, {"n": 88, "q": "What does the speaker ask supervisors to do?", "opts": ["Reward staff for their efficiency", "Review marketing strategies with their teams", "Schedule team-building exercises", "Recommend staff for promotions"], "ans": 1, "ko": "화자가 후반부에 모든 책임자들은 상품과 서비스를 고객에게 홍보할 전략에 대해 소속 직원들과 이야기해 주길 원한다(I'd like all supervisors to talk to their staff about strategies to pitch our products and services to customers)고 했으므로 정답은 (B) 팀원들과 마케팅 전략 살펴보기이다."}], "script": [{"sp": "M", "en": "You may remember that our bank branch was evaluated by auditors from our headquarters last week. Well, I received their report today. They looked at everything from how we handle recordkeeping for accounts and transactions to how our bank tellers interact with individual customers. Above all, they were impressed with the quality of our customer service, specifically how we greet customers and direct them to the right associate. However, we received low ratings on marketing our other products. I'd like all supervisors to talk to their staff about strategies to pitch our products and services to customers.", "ko": "지난주에 우리 은행 지점이 본사 회계 감사관으로부터 평가를 받은 것을 기억하실 것입니다. 음, 오늘 그들의 보고서를 받았습니다. 그들은 계좌와 거래의 기록을 보관하는 방식부터 은행원들이 개별 고객과 소통하는 방식까지 모든 부분을 살펴봤습니다. 무엇보다, 그들은 고객 서비스 품질, 특히 우리가 고객들을 맞이하고 적절한 직원에게 안내해 드리는 방식에 깊은 인상을 받았습니다. 하지만 우리의 다른 상품을 마케팅하는 일에 대해서는 낮은 등급을 받았습니다. 모든 책임자들은 우리 상품과 서비스를 고객들께 홍보할 전략에 대해 소속 직원들과 이야기해 주셨으면 합니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test_03-89-91.mp3", "qs": [{"n": 89, "q": "Why does the speaker call employees in early?", "opts": ["He wants to pass out some gifts.", "He expects a busy night.", "The owner will give a speech.", "New uniforms have arrived."], "ans": 1, "ko": "화자가 초반부에 청자들이 일찍 와서 기쁘다는 말과 함께 여섯 개의 대규모 단체 예약이 추가되어 이례적으로 바쁜 밤을 앞두고 있다(We have an unusually busy night ahead of us—due to the addition of six large group reservations)고 했으므로 정답은 (B)이다."}, {"n": 90, "q": "What should be retrieved from storage?", "opts": ["Promotional signs", "Heat lamps", "Extra tables", "Storage containers"], "ans": 2, "ko": "화자가 중반부에 테이블들을 창고에서 꺼내 와야 할 것(Tables will need to come out of storage, ~)이라고 했으므로 정답은 (C)이다. Paraphrasing: 담화의 come out of storage → 질문의 be retrieved from storage"}, {"n": 91, "q": "What does the speaker mean when he says, \"Management will be watching closely\"?", "opts": ["A decision about an item will be made soon.", "A client may not renew a contract.", "A large profit is expected.", "More people might be hired."], "ans": 0, "ko": "화자가 후반부에 송로 버섯 요리 홍보를 강조하며, 정식 메뉴로 도입할 수 있을지 알아보려고 한다(We'd like to see if this could be a permanent menu item)는 말과 함께 인용문을 언급했다. 따라서 경영진이 해당 메뉴에 대한 결정을 내리려고 한다는 것을 알 수 있으므로 (A)가 정답이다."}], "script": [{"sp": "M", "en": "Oh good. I'm glad to see everyone is here early, as requested. We have an unusually busy night ahead of us—due to the addition of six large group reservations. We'll set up for those first in the overflow room. Tables will need to come out of storage. I'll unlock the door after this meeting. But before you start your shift, make sure to try tonight's specials. They're in their usual spot under the heat lamps. Be sure you promote the truffles dish in particular. We'd like to see if this could be a permanent menu item. Management will be watching closely. Its price point is high, but it really is delicious.", "ko": "아, 좋습니다. 요청대로, 모두 이곳에 일찍 와 계신 것을 보니 기쁩니다. 여섯 개의 대규모 단체 예약이 추가되어 이례적으로 바쁜 밤을 앞두고 있습니다. 우리는 먼저 초과 인원을 위한 공간에 자리를 마련할 것입니다. 테이블들은 창고에서 꺼내 와야 합니다. 회의가 끝나고 그 문을 열어 드릴게요. 그런데 근무를 시작하시기 전에, 오늘 밤의 특별 메뉴를 꼭 시식해 보세요. 평소와 같은 자리인 보온용 전등 아래에 있습니다. 특히 송로 버섯 요리를 적극 홍보해 주세요. 정식 메뉴로 도입할 수 있을지 알아보려고 합니다. 경영진이 면밀히 지켜볼 예정입니다. 가격대가 높긴 하지만, 정말 맛있습니다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test_03-92-94.mp3", "qs": [{"n": 92, "q": "What type of news is the broadcast about?", "opts": ["Travel", "Art", "Financial", "Sports"], "ans": 2, "ko": "화자가 초반부에 WBCO 경제 뉴스에 온 것을 환영한다(~ welcome to WBCO financial news)고 했으므로 정답은 (C)이다."}, {"n": 93, "q": "Why does the speaker say, \"That technology is now widely available\"?", "opts": ["To praise a marketing plan", "To recommend a computer application", "To explain the growth of a trend", "To correct some wrong information"], "ans": 2, "ko": "화자가 중반부에 이런 경향은 대형 항공사가 수요를 추적하여 항공권 가격을 신속하게 변경할 수 있게 하는 컴퓨터 소프트웨어에서 처음 시작되었다(~ this trend first started with computer software that allowed large airlines ~)면서 인용문을 언급하고 있다. 따라서 그러한 경향이 현재 널리 이용되고 있을 정도로 증가했음을 알리기 위해 한 말이라는 것을 알 수 있으므로 정답은 (C)이다."}, {"n": 94, "q": "What did Professor Yun Hang do last month?", "opts": ["He spoke at a conference.", "He published a book.", "He started a business.", "He won an award."], "ans": 0, "ko": "화자가 후반부에 윤 항 교수를 소개하면서 지난달에는 국제 경제 정상 회의에서 특별 연사로 참여했다(Last month he was the featured speaker at the International Economics Summit)고 했으므로 정답은 (A)이다. Paraphrasing: 담화의 the featured speaker at the International Economics Summit → 정답의 spoke at a conference"}], "script": [{"sp": "W", "en": "Hello, and welcome to WBCO financial news. Tonight, we're talking about the prices we pay online for goods and services. In particular, we'll look at why you may pay more if you shop during times of peak demand. Called surge pricing, this trend first started with computer software that allowed large airlines to track demand and quickly change their ticket prices. That technology is now widely available. You may find that even small businesses charge more when demand is higher. Our guest today is Professor Yun Hang, a leading expert on the topic. Last month he was the featured speaker at the International Economics Summit.", "ko": "안녕하세요, WBCO 경제 뉴스에 오신 것을 환영합니다. 오늘 밤, 온라인에서 상품과 서비스를 구매할 때 지불하는 가격에 대해 이야기해 보겠습니다. 특히, 수요가 많은 시기에 쇼핑을 하면 더 많은 비용을 지불하게 되는 이유를 살펴볼 것입니다. 가격 급등 현상이라고 부르는 이런 경향은 대형 항공사가 수요를 추적하여 항공권 가격을 신속하게 변경할 수 있게 하는 컴퓨터 소프트웨어에서 처음 시작되었습니다. 이 기술은 이제 널리 이용되고 있습니다. 심지어 작은 업체들도 수요가 많을 때 더 많은 비용을 청구하는 경우를 볼 수 있습니다. 오늘 초대 손님은 윤 항 교수님이며, 이 분야의 손꼽히는 전문가입니다. 지난달에는 국제 경제 정상 회의에서 특별 연사로 참여했습니다."}]}, {"start": 95, "part": 3, "intro": "", "graphic": true, "speakers": "M-Au", "audio": "Test_03-95-97.mp3", "qs": [{"n": 95, "q": "Why is the speaker calling?", "opts": ["To file a complaint", "To purchase some tickets", "To revise an order", "To promote a product"], "ans": 2, "ko": "화자가 초반부에 원래 금요일까지 필요하다고 말한 쿠폰이 이제는 수요일까지 준비되어야 한다(We originally said we needed the coupons by Friday, but we now need them to be ready by Wednesday instead)고 말하고 있다. 이는 쿠폰 출력 주문에 대한 기한을 변경하겠다는 뜻이므로 정답은 (C)이다."}, {"n": 96, "q": "What did the speaker find out yesterday?", "opts": ["A printer was replaced.", "An application was approved.", "A sales event was announced.", "A lease was extended."], "ans": 1, "ko": "화자가 중반부에 전국 플로리스트 협회에 낸 신청서가 승인되었다는 사실을 어제 막 알게 되었다(We just found out yesterday that our application to the National Florists Association was approved)고 했으므로 정답은 (B)이다."}, {"n": 97, "q": "Look at the graphic. Which number does the speaker want to change?", "opts": ["2005", "25", "2", "6"], "ans": 2, "ko": "화자가 후반부에 쿠폰의 적용 한도를 5개 제품으로 변경하고 싶다(~ we'd also like to change the limit to five items on the coupon)고 했는데, 쿠폰에 한정 제품 수량이 2로 나와 있으므로 정답은 (C)이다."}], "script": [{"sp": "M", "en": "Hi. This is Liam from Oceania Flowers. I'm calling about our print order for coupons. We originally said we needed the coupons by Friday, but we now need them to be ready by Wednesday instead. We just found out yesterday that our application to the National Florists Association was approved. We'll be attending their annual Floral Show in Richmond this weekend. Oh, one other thing—we'd also like to change the limit to five items on the coupon. Can you take care of that before you start printing? Thank you!", "ko": "안녕하세요. 저는 오셔니아 플라워즈의 리암입니다. 저희 쿠폰 출력 주문과 관련해 전화 드립니다. 원래는 금요일까지 쿠폰이 필요하다고 말씀을 드렸었는데, 이제는 수요일까지 준비되어야 합니다. 전국 플로리스트 협회에 낸 신청서가 승인되었다는 사실을 어제 막 알게 되었어요. 이번 주말 리치몬드에서 열리는 이 협회의 연례 꽃 박람회에 참석할 예정입니다. 아, 다른 한 가지가 더 있는데, 쿠폰의 적용 한도를 5개 제품으로 변경하고 싶어요. 출력을 시작하기 전에 이 부분을 처리해 주시겠어요? 감사합니다!"}], "gimg": "ets_t3_g95.jpg"}, {"start": 98, "part": 3, "intro": "", "graphic": true, "speakers": "M-Cn", "audio": "Test_03-98-100.mp3", "qs": [{"n": 98, "q": "Who most likely is the listener?", "opts": ["An actor", "A photographer", "A writer", "An athlete"], "ans": 0, "ko": "화자가 초반부에 좋은 소식이라는 말과 함께 청자가 첫 번째 텔레비전 오디션 기회를 얻었고, 그것이 TV 드라마 배역(Good news—you got your first television audition! It's for a role in a TV drama)이라고 했으므로 정답은 (A)이다."}, {"n": 99, "q": "According to the speaker, what should the listener do to prepare?", "opts": ["Update a résumé", "Review some videos", "Contact a colleague", "Make a recording"], "ans": 1, "ko": "화자가 중반부에 이전 방송분을 시청해서 배역을 이해해야 한다(~ you should watch some videos of previous episodes so you understand the role)고 했으므로 정답은 (B)이다. Paraphrasing: 담화의 watch some videos of previous episodes → 정답의 Review some videos"}, {"n": 100, "q": "Look at the graphic. Which bus stop does the speaker recommend getting off at?", "opts": ["Orchard", "Heath", "Grove", "Meadow"], "ans": 2, "ko": "화자가 후반부에 황색 노선을 이용해 마지막 정거장까지 가는 것을 권한다(~ I'd recommend taking the yellow line to the last stop)고 했는데, 버스 노선도에서 황색 노선의 마지막 정거장은 그로브이므로 정답은 (C)이다."}], "script": [{"sp": "M", "en": "Hi, Takuma. Good news—you got your first television audition! It's for a role in a TV drama. I've sent an e-mail with the script and details. Since you're auditioning to join the cast of an ongoing show, you should watch some videos of previous episodes so you understand the role. One last note—since you're new to the city, you might be wondering about the best bus route to take. You could take the green line to Orchard, but I'd recommend taking the yellow line to the last stop. It's a longer route, but the last stop is closer to the studio.", "ko": "안녕하세요, 타쿠마. 좋은 소식이 있어요. 첫 번째 텔레비전 오디션 기회를 얻으셨어요! TV 드라마 배역이에요. 대본과 상세 정보를 이메일로 보냈어요. 진행 중인 프로그램의 출연진에 합류하기 위해 오디션을 보는 것이라서, 이전 방송분을 시청해서 배역을 이해해야 해요. 마지막 한 가지 전달 사항이에요. 이 도시에 처음이시니, 어떤 버스를 타야 가장 좋을지 궁금하실 거예요. 녹색 노선을 타고 오차드로 가실 수도 있겠지만, 황색 노선을 이용해 마지막 정거장까지 가시는 것을 권해 드려요. 경로가 더 길지만, 마지막 정거장이 스튜디오와 더 가깝습니다."}], "gimg": "ets_t3_g98.jpg"}]};
